async function main() {
  const items = $input.all();

  for (let i = 0; i < items.length; i++) {
    const item = items[i];

    // 1) Liste des binaires disponibles
    const keys = Object.keys(item.binary ?? {});
    if (!keys.length) continue;

    // 2) Trouver le logo + 1-2 visuals (par nom de fichier)
    const findByName = (needle) =>
      keys.find(k => (item.binary[k]?.fileName || '').toLowerCase().includes(needle));

    const logoKey = findByName('logo');

    const visualKeys = keys
      .filter(k => (item.binary[k]?.fileName || '').toLowerCase().includes('visual'))
      .slice(0, 2);

    // fallback si pas de match "visual"
    const fallbackVisuals = keys.filter(k => k !== logoKey).slice(0, 2);

    const selected = {
      logoKey,
      visualKeys: visualKeys.length ? visualKeys : fallbackVisuals,
    };

    // 3) Lire les vrais fichiers (filesystem mode) -> base64
    const out = {};

    if (selected.logoKey) {
      const buf = await this.helpers.getBinaryDataBuffer(i, selected.logoKey);
      out.logo = {
        fileName: item.binary[selected.logoKey].fileName,
        mimeType: item.binary[selected.logoKey].mimeType,
        base64: buf.toString('base64'),
      };
    }

    out.visuals = [];
    for (const k of selected.visualKeys) {
      const buf = await this.helpers.getBinaryDataBuffer(i, k);
      out.visuals.push({
        fileName: item.binary[k].fileName,
        mimeType: item.binary[k].mimeType,
        base64: buf.toString('base64'),
      });
    }

    item.json.brandAssets = out; // <-- tu utiliseras ça dans le HTTP
  }

  return items;
}

return main();

