// 1) Récupère le texte brut renvoyé par Gemini (contient ```json ... ```)
const text = $node["generate_ad_image_prompt1"].json.candidates[0].content.parts[0].text || "";

// 2) Nettoie les fences ```json ... ```
const cleaned = text
  .replace(/```json\s*/i, "")
  .replace(/```/g, "")
  .trim();

// 3) Parse le JSON
const obj = JSON.parse(cleaned);

// 4) Transforme variants[] en items n8n (1 item = 1 prompt image)
return (obj.variants || []).map(v => ({
  json: {
    variantId: v.id,
    imagePrompt: v.imagePrompt,
    onImageText: v.onImageText,
    layout: v.layout,
    style: v.style
  }
}));
